function parseRSS(xmlString) {
  const articles = [];

  try {
    // Detect source from channel title
    const channelTitleMatch = 
      xmlString.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/) ||
      xmlString.match(/<title>([^<]{1,100})<\/title>/);

    let sourceName = 'Unknown';
    if (channelTitleMatch) {
      sourceName = channelTitleMatch[1]
        .replace(/<[^>]*>/g, '')
        .trim()
        .substring(0, 40);
    }

    // Handle Atom feed format (The Verge uses this)
    const isAtomFeed = xmlString.includes('<feed xmlns');

    let itemRegex;
    if (isAtomFeed) {
      itemRegex = /<entry>([\s\S]*?)<\/entry>/g;
    } else {
      itemRegex = /<item>([\s\S]*?)<\/item>/g;
    }

    let match;
    let count = 0;

    while ((match = itemRegex.exec(xmlString)) !== null && count < 5) {
      const item = match[1];

      // Title extraction
      const titleMatch = 
        item.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/) ||
        item.match(/<title[^>]*type="html"[^>]*><!\[CDATA\[([\s\S]*?)\]\]><\/title>/) ||
        item.match(/<title[^>]*>([\s\S]{1,200}?)<\/title>/);

      // Link extraction — handles both RSS and Atom formats
      const linkMatch = 
        item.match(/<link rel="alternate"[^>]*href="([^"]*)"/) ||
        item.match(/<link rel="alternate" href="([^"]*)"/) ||
        item.match(/<link[^>]+href="(https?:\/\/[^"]+)"/) ||
        item.match(/<link href="([^"]*)"/) ||
        item.match(/<link>(https?:\/\/[^<]*)<\/link>/) ||
        item.match(/<id>(https?:\/\/[^<]*)<\/id>/);

      // Description extraction
      const descMatch = 
        item.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/) ||
        item.match(/<summary[^>]*><!\[CDATA\[([\s\S]*?)\]\]><\/summary>/) ||
        item.match(/<summary[^>]*>([\s\S]*?)<\/summary>/) ||
        item.match(/<description>([\s\S]*?)<\/description>/);

      // Date extraction
      const dateMatch = 
        item.match(/<pubDate>(.*?)<\/pubDate>/) ||
        item.match(/<published>(.*?)<\/published>/) ||
        item.match(/<updated>(.*?)<\/updated>/);

      if (titleMatch && linkMatch) {
        const title = titleMatch[1]
          .replace(/<[^>]*>/g, '')
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>')
          .replace(/&quot;/g, '"')
          .trim();

        const link = linkMatch[1].trim();

        const description = descMatch
          ? descMatch[1]
              .replace(/<[^>]*>/g, '')
              .replace(/&amp;/g, '&')
              .replace(/&lt;/g, '<')
              .replace(/&gt;/g, '>')
              .trim()
              .substring(0, 300)
          : 'No description available';

        const pubDate = dateMatch
          ? dateMatch[1].trim()
          : 'Unknown date';

        if (title && title.length > 5 && link.startsWith('http')) {
          articles.push({
            source: sourceName,
            title,
            link,
            description,
            pubDate
          });
          count++;
        }
      }
    }
  } catch(e) {
    console.log('Parse error:', e.message);
  }

  return articles;
}

// Get all items from all connected nodes
const allItems = $input.all();
let allArticles = [];

allItems.forEach((item) => {
  const xmlData = item.json.data;
  if (xmlData && typeof xmlData === 'string') {
    const articles = parseRSS(xmlData);
    allArticles = allArticles.concat(articles);
  }
});

// Format digest text for Gemini
const articleDigest = allArticles.map((article, index) => {
  return `[${index + 1}] SOURCE: ${article.source}
Title: ${article.title}
Date: ${article.pubDate}
Summary: ${article.description}
Link: ${article.link}`;
}).join('\n\n---\n\n');

return [{
  json: {
    total_articles: allArticles.length,
    articles: allArticles,
    digest_text: articleDigest,
    generated_at: new Date().toISOString()
  }
}];

// Get the briefing from Gemini
const briefing = $json.output;

// Clean up the text
const cleanBriefing = briefing
  // Remove markdown bold
  .replace(/\*\*(.*?)\*\*/g, '$1')
  // Remove markdown headers
  .replace(/##\s/g, '')
  .replace(/#\s/g, '')
  // Clean up excessive newlines
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Create a Slack-friendly version
// Slack uses *text* for bold instead of **text**
const slackBriefing = cleanBriefing
  .replace(/TOP STORIES TODAY:/g, '*TOP STORIES TODAY:*')
  .replace(/AI & AUTOMATION SPOTLIGHT:/g, '*AI & AUTOMATION SPOTLIGHT:*')
  .replace(/PHILIPPINES & BUSINESS:/g, '*PHILIPPINES & BUSINESS:*')
  .replace(/TODAY\'S KEY TAKEAWAY:/g, '*TODAY\'S KEY TAKEAWAY:*')
  .replace(/QUICK READS:/g, '*QUICK READS:*');

// Get today's date for subject line
const today = new Date();
const dateString = today.toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

return [{
  json: {
    briefing_text: cleanBriefing,
    slack_briefing: slackBriefing,
    email_subject: `Your AI & Tech Morning Briefing — ${dateString}`,
    generated_at: new Date().toISOString()
  }
}];
